import{_ as e}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o,c as i,a2 as s}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Etiquetagem automática","description":"","frontmatter":{},"headers":[],"relativePath":"pt-BR/Other/auto-tagging.md","filePath":"pt-BR/Other/auto-tagging.md","lastUpdated":1781962217000}'),r={name:"pt-BR/Other/auto-tagging.md"};function d(c,a,n,l,p,u){return o(),i("div",null,[...a[0]||(a[0]=[s('<h1 id="etiquetagem-automatica" tabindex="-1">Etiquetagem automática <a class="header-anchor" href="#etiquetagem-automatica" aria-label="Permalink to &quot;Etiquetagem automática&quot;">​</a></h1><p>A etiquetagem automática é configurada em:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configurações do sistema -&gt; Outras configurações -&gt; Etiquetagem automática</span></span></code></pre></div><p>Ela gera tags para imagens e facilita busca, filtros da API aleatória, galeria pública e controle de acesso por classificação etária.</p><h2 id="o-que-ela-faz" tabindex="-1">O que ela faz <a class="header-anchor" href="#o-que-ela-faz" aria-label="Permalink to &quot;O que ela faz&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Recurso</th><th>Descrição</th></tr></thead><tbody><tr><td>Tags de conteúdo</td><td>Adiciona tags de pessoas, cenas, objetos, estilo visual e outros elementos</td></tr><tr><td>Tags de personagem</td><td>Útil para imagens de anime e ilustrações</td></tr><tr><td>Tags de orientação</td><td>Adiciona <code>landscape</code>, <code>portrait</code> ou <code>square</code></td></tr><tr><td>Classificação da imagem</td><td>Salva resultados <code>G/S/Q/E</code></td></tr><tr><td>Etiquetar ao enviar</td><td>Processa automaticamente imagens novas</td></tr><tr><td>Etiquetagem em lote</td><td>Adiciona tags a imagens antigas em uma ou várias pastas</td></tr></tbody></table><h2 id="o-que-preparar" tabindex="-1">O que preparar <a class="header-anchor" href="#o-que-preparar" aria-label="Permalink to &quot;O que preparar&quot;">​</a></h2><p>Você precisa de pelo menos uma URL acessível de Hugging Face Space.</p><p>O recomendado é duplicar o Space <code>wd-tagger</code> do SmilingWolf na sua própria conta do Hugging Face:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Você pode usar o Space público para testes, mas ele é compartilhado por muitos usuários e pode ter fila, lentidão ou indisponibilidade. Para uso contínuo, uma cópia própria é mais estável.</p><h2 id="duplicar-o-space" tabindex="-1">Duplicar o Space <a class="header-anchor" href="#duplicar-o-space" aria-label="Permalink to &quot;Duplicar o Space&quot;">​</a></h2><ol><li>Entre no Hugging Face.</li><li>Abra <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+e+`" alt="Space público do SmilingWolf" loading="lazy"></p><ol start="3"><li>Abra o menu no canto superior direito.</li><li>Escolha <code>Duplicate this Space</code>.</li><li>Mantenha o nome ou use algo fácil de reconhecer, como <code>wd-tagger</code>.</li><li>Deixe como <code>Public</code>; assim o ImgBed consegue chamar com menos atrito.</li><li>Comece com o hardware gratuito.</li><li>Crie o Space e aguarde a build terminar.</li></ol><p>Depois, copie a URL do navegador e cole em <code>Space URLs</code> no ImgBed.</p><h2 id="configuracoes-recomendadas" tabindex="-1">Configurações recomendadas <a class="header-anchor" href="#configuracoes-recomendadas" aria-label="Permalink to &quot;Configurações recomendadas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Opção</th><th>Recomendação</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Uma URL por linha</td></tr><tr><td>Pasta alvo</td><td>Vazio para todas; selecione uma pasta se quiser limitar</td></tr><tr><td>Modelo</td><td>Comece com <code>wd-swinv2-tagger-v3</code></td></tr><tr><td>Limiar de tags gerais</td><td>Comece perto de <code>0.35</code></td></tr><tr><td>Limiar de personagens</td><td>Comece perto de <code>0.85</code> para reduzir falso positivo</td></tr><tr><td><code>MCut</code></td><td>Deixe desligado no início</td></tr><tr><td>Etiquetar ao enviar</td><td>Ative se quiser processar imagens novas automaticamente</td></tr></tbody></table><p>Se vierem tags demais, suba um pouco o limiar geral. Se vierem poucas, reduza levemente.</p><h2 id="etiquetagem-em-lote" tabindex="-1">Etiquetagem em lote <a class="header-anchor" href="#etiquetagem-em-lote" aria-label="Permalink to &quot;Etiquetagem em lote&quot;">​</a></h2><ol><li>Preencha <code>Space URLs</code>.</li><li>Escolha uma pasta alvo.</li><li>Inicie a etiquetagem.</li><li>Aguarde o progresso terminar.</li></ol><p>Se a pasta alvo estiver vazia, o ImgBed processa todas as pastas.</p><h2 id="etiquetar-ao-enviar" tabindex="-1">Etiquetar ao enviar <a class="header-anchor" href="#etiquetar-ao-enviar" aria-label="Permalink to &quot;Etiquetar ao enviar&quot;">​</a></h2><p>Com essa opção ativa, imagens novas chamam automaticamente os <code>Space URLs</code> configurados.</p><p>Se o Space estiver em fila, o upload pode terminar primeiro e a etiquetagem continuar em segundo plano.</p><h2 id="perguntas-comuns" tabindex="-1">Perguntas comuns <a class="header-anchor" href="#perguntas-comuns" aria-label="Permalink to &quot;Perguntas comuns&quot;">​</a></h2><h3 id="por-que-duplicar-meu-proprio-space" tabindex="-1">Por que duplicar meu próprio Space? <a class="header-anchor" href="#por-que-duplicar-meu-proprio-space" aria-label="Permalink to &quot;Por que duplicar meu próprio Space?&quot;">​</a></h3><p>Spaces públicos são compartilhados por muita gente. Uma cópia própria costuma ser mais rápida e estável para seu site.</p><h3 id="por-que-as-tags-saem-em-ingles" tabindex="-1">Por que as tags saem em inglês? <a class="header-anchor" href="#por-que-as-tags-saem-em-ingles" aria-label="Permalink to &quot;Por que as tags saem em inglês?&quot;">​</a></h3><p>Isso é normal. Os modelos do SmilingWolf retornam tags em inglês. O ImgBed usa essas tags para busca, filtros, API aleatória e galeria pública.</p><h3 id="para-que-serve-a-classificacao" tabindex="-1">Para que serve a classificação? <a class="header-anchor" href="#para-que-serve-a-classificacao" aria-label="Permalink to &quot;Para que serve a classificação?&quot;">​</a></h3><p>A classificação trabalha junto com o modo de acesso em Segurança. Por exemplo, ao limitar visitantes por classificação etária, a galeria e a API aleatória seguem essas regras.</p><h2 id="fluxo-rapido" tabindex="-1">Fluxo rápido <a class="header-anchor" href="#fluxo-rapido" aria-label="Permalink to &quot;Fluxo rápido&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrar no Hugging Face</span></span>
<span class="line"><span>-&gt; Abrir SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicar o Space</span></span>
<span class="line"><span>-&gt; Aguardar build</span></span>
<span class="line"><span>-&gt; Copiar URL do Space</span></span>
<span class="line"><span>-&gt; Colar em Space URLs</span></span>
<span class="line"><span>-&gt; Ajustar modelo e limiares</span></span>
<span class="line"><span>-&gt; Iniciar etiquetagem ou ativar etiquetar ao enviar</span></span></code></pre></div>`,34)])])}const q=t(r,[["render",d]]);export{h as __pageData,q as default};
